// // This module uses NAND gates to implement a 2-to-1 multiplexer. When S is high, Y should be equal to B, and when S is low, Y should be equal to A.
module MUX2N1 (A, B, S, Y);
input A;
input B;
input S;
output Y;

wire nand1_out;
wire nand2_out;
wire nand3_out;

nand nand1 (nand1_out, A, S);
nand nand2 (nand2_out, B, !S);
nand nand3 (Y, nand1_out, nand2_out);

endmodule
